section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/e2e-testing",
  "type": "object",
  "required": ["playwrightConfig", "pages", "fixtures", "specs"],
  "properties": {
    "playwrightConfig": {
      "type": "string",
      "description": "Path to playwright.config.ts; must declare projects array with at least chromium, must set retries>=1 in CI, must set trace='on-first-retry'."
    },
    "pages": {
      "type": "array",
      "description": "Page Object files at e2e/pages/*.ts. Each exports a class with constructor(page: Page), goto(), and >=1 intent-named method.",
      "items": {"type": "string", "pattern": "^e2e/pages/[A-Z][A-Za-z0-9]*\\.ts$"},
      "minItems": 1
    },
    "fixtures": {
      "type": "string",
      "description": "e2e/fixtures.ts exporting `test` extended from @playwright/test with at least one custom fixture."
    },
    "specs": {
      "type": "array",
      "description": "Test files at e2e/*.spec.ts. <=50 in the @critical/@smoke tag bucket.",
      "items": {"type": "string", "pattern": "^e2e/.+\\.spec\\.ts$"},
      "maxItems": 50
    },
    "forbidden": {
      "type": "array",
      "description": "Patterns that must NOT appear anywhere in e2e/.",
      "items": {"enum": [
        "page.waitForTimeout",
        "page.locator('css=",
        "{ force: true }",
        "page.locator('//",
        "describe.only",
        "test.only"
      ]}
    }
  }
}

example.code:
// e2e/login.spec.ts — REJECTED by validate-e2e-testing.py
test('login works', async ({ page }) => {
  await page.goto('/login');
  await page.locator('#email-input-1234').fill('a@b.com');   // dynamic CSS ID
  await page.locator('button.submit').click({ force: true }); // force bypass
  await page.waitForTimeout(3000);                            // hard sleep
  expect(await page.url()).toContain('/dashboard');           // raw url assert, no auto-retry
});
